import{_ as e,o as l,c as d,ag as a}from"./chunks/framework.DTiDeF2Q.js";const x=JSON.parse('{"title":"Permission 别名 | Dotfiles (ZH)","titleTemplate":":title","description":"chmod、chown 和 chgrp 命令的 shell 别名。使用数字快捷方式（如 755、644 和 777）快速设置文件权限。","frontmatter":{"title":"Permission 别名 | Dotfiles","description":"chmod、chown 和 chgrp 命令的 shell 别名。使用数字快捷方式（如 755、644 和 777）快速设置文件权限。","lang":"zh-CN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Permission 别名 preview","canonical":"/zh/aliases/permission/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Permission 别名","pageType":"docs","schemaType":"WebPage","metaTitle":"Permission 别名 - Dotfiles (CN)","permalink":"/zh/aliases/permission/","sidebar":true,"meta":[{"name":"keywords","content":"权限别名, chmod 快捷方式, 文件权限, chown, chgrp, dotfiles, shell"}]},"headers":[],"relativePath":"zh/aliases/permission/index.md","filePath":"zh/aliases/permission/index.md","lastUpdated":1773010926000}'),i={name:"zh/aliases/permission/index.md"};function s(o,t,r,n,c,h){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="permission-别名" tabindex="-1">Permission 别名 <a class="header-anchor" href="#permission-别名" aria-label="Permalink to &quot;Permission 别名&quot;">​</a></h1><p>在 shell 环境中管理文件和目录权限的快捷方式。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>这些别名定义在 <code>permission.aliases.sh</code> 中，由 chezmoi 自动加载。它们提供对常见权限模式和所有权命令的快速访问。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><h3 id="数字权限快捷方式" tabindex="-1">数字权限快捷方式 <a class="header-anchor" href="#数字权限快捷方式" aria-label="Permalink to &quot;数字权限快捷方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>000</code></td><td style="text-align:left;">将权限设置为用户、组和其他人都没有读写执行权限</td></tr><tr><td style="text-align:left;"><code>400</code></td><td style="text-align:left;">将权限设置为无读写，但仅允许用户执行</td></tr><tr><td style="text-align:left;"><code>444</code></td><td style="text-align:left;">将权限设置为无写入或执行，但允许所有人读取</td></tr><tr><td style="text-align:left;"><code>600</code></td><td style="text-align:left;">将权限设置为仅用户读写</td></tr><tr><td style="text-align:left;"><code>644</code></td><td style="text-align:left;">将权限设置为所有人可读，但仅用户可写</td></tr><tr><td style="text-align:left;"><code>666</code></td><td style="text-align:left;">将权限设置为所有人可读写</td></tr><tr><td style="text-align:left;"><code>755</code></td><td style="text-align:left;">将权限设置为用户读写执行，组和其他人读执行</td></tr><tr><td style="text-align:left;"><code>764</code></td><td style="text-align:left;">将权限设置为用户和组读写，其他人只读</td></tr><tr><td style="text-align:left;"><code>777</code></td><td style="text-align:left;">将权限设置为所有人读写执行</td></tr></tbody></table><h3 id="文件模式命令" tabindex="-1">文件模式命令 <a class="header-anchor" href="#文件模式命令" aria-label="Permalink to &quot;文件模式命令&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod</code></td><td style="text-align:left;">更改文件模式位</td></tr><tr><td style="text-align:left;"><code>chmodr</code></td><td style="text-align:left;">递归更改文件模式位</td></tr><tr><td style="text-align:left;"><code>chmodu</code></td><td style="text-align:left;">递归更改文件模式位为当前用户</td></tr><tr><td style="text-align:left;"><code>chmox</code></td><td style="text-align:left;">使文件可执行</td></tr></tbody></table><h3 id="所有权命令" tabindex="-1">所有权命令 <a class="header-anchor" href="#所有权命令" aria-label="Permalink to &quot;所有权命令&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chown</code></td><td style="text-align:left;">更改文件所有者和组</td></tr><tr><td style="text-align:left;"><code>chownr</code></td><td style="text-align:left;">递归更改文件所有者和组</td></tr><tr><td style="text-align:left;"><code>chownu</code></td><td style="text-align:left;">递归更改文件所有者和组为当前用户</td></tr><tr><td style="text-align:left;"><code>chgrp</code></td><td style="text-align:left;">更改文件或目录的组所有权</td></tr><tr><td style="text-align:left;"><code>chgrpr</code></td><td style="text-align:left;">递归更改文件或目录的组所有权</td></tr><tr><td style="text-align:left;"><code>chgrpu</code></td><td style="text-align:left;">递归更改文件或目录的组所有权为当前用户</td></tr></tbody></table>',11)])])}const g=e(i,[["render",s]]);export{x as __pageData,g as default};
